//! bench-hope-jar-hybrid — the bootstrap/startup win, measured.
//!
//! "Use both": boot on the tiny latent E8 generator (instant cold start),
//! then memoize hot slots into a materialized cache for warm-path speed.
//! This bench measures the two things the hybrid is actually for:
//!   1. time-to-first-key from cold disk (the startup win)
//!   2. cold-slot (regen) vs hot-slot (cached) discharge once running
//! Release-only numbers (build with --release).

use distributed_inference::hope_jar::HopeJar;
use distributed_inference::hope_jar_e8::HopeJarE8;
use distributed_inference::hope_jar_hybrid::HybridHopeJar;
use std::hint::black_box;
use std::time::Instant;

fn main() {
    let monster_bytes = std::fs::read("rknots/hope-jar.rknot")
        .expect("rknots/hope-jar.rknot (run from distributed-inference/)");
    let e8_bytes = std::fs::read("rknots/hope-jar-e8.rknot").expect("rknots/hope-jar-e8.rknot");

    // ── 1. BOOTSTRAP: time from cold bytes to first ANSWER ──
    // The real startup win is the O(1) point query: a freshly-loaded E8 jar
    // answers a predict() immediately with NO materialization. The Monster
    // jar has no predict; its first key needs the full 196884-key
    // materialization that decode_seeds does up front. Median of several
    // runs (these are us-scale and allocation-noisy).
    let runs = 9;
    let mut boot_pred = Vec::new();
    let mut boot_mon = Vec::new();
    for _ in 0..runs {
        let t = Instant::now();
        let e8 = HopeJarE8::decode_rknot(&e8_bytes).expect("e8");
        let p = e8.predict(0xABCD_1234);
        boot_pred.push(t.elapsed().as_nanos() as f64 / 1000.0);
        black_box(p);

        let t = Instant::now();
        let mut m = HopeJar::decode_seeds(&monster_bytes).expect("monster");
        let k = m.discharge(0, 0).first().copied().unwrap_or(0);
        boot_mon.push(t.elapsed().as_nanos() as f64 / 1000.0);
        black_box(k);
    }
    boot_pred.sort_by(|a, b| a.partial_cmp(b).unwrap());
    boot_mon.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let med_pred = boot_pred[runs / 2];
    let med_mon = boot_mon[runs / 2];

    // ── 2. WARM discharge, keys ACTUALLY consumed ──
    // cold slot = regenerate 96768 keys and sum them; hot slot = sum the
    // memoized slice. This is the honest regen-vs-memory-read comparison.
    let e8 = HopeJarE8::decode_rknot(&e8_bytes).expect("e8");
    let mut hybrid = HybridHopeJar::new(e8);
    let mut acc = 0u64;

    let mut cold_ns = 0u128;
    let mut cold_keys = 0u64;
    for r in 0..32u64 {
        let phase = (r % 30) as u8;
        let lane = ((r * 7 + 1) % 240) as u8;
        let t = Instant::now();
        let slot = hybrid.discharge(phase, lane); // first touch: regen
        for &k in slot {
            acc ^= k;
        } // CONSUME every key
        cold_ns += t.elapsed().as_nanos();
        cold_keys += slot.len() as u64;
    }
    let cold_kps = cold_keys as f64 / (cold_ns as f64 / 1e9);

    let mut hot_ns = 0u128;
    let mut hot_keys = 0u64;
    for _pass in 0..50 {
        for r in 0..32u64 {
            let phase = (r % 30) as u8;
            let lane = ((r * 7 + 1) % 240) as u8;
            let t = Instant::now();
            let slot = hybrid.discharge(phase, lane); // cached: memory read
            for &k in slot {
                acc ^= k;
            } // CONSUME every key
            hot_ns += t.elapsed().as_nanos();
            hot_keys += slot.len() as u64;
        }
    }
    let hot_kps = hot_keys as f64 / (hot_ns as f64 / 1e9);
    black_box(acc);
    let warm_speedup = hot_kps / cold_kps;

    let per_slot_kb = 96768.0 * 8.0 / 1e3;
    let monster_budget_slots = 1_575_087.0 / (96768.0 * 8.0);

    println!(
        "=== HYBRID HOPE JAR — bootstrap + warm (release, median of {}) ===\n",
        runs
    );
    println!("-- 1. cold boot: time-to-first-ANSWER from disk --");
    println!(
        "  E8 predict() (no materialize): {:>8.1} us   load {:.1}KB + O(1) query",
        med_pred,
        e8_bytes.len() as f64 / 1e3
    );
    println!(
        "  Monster first key (materialize): {:>6.1} us   load+expand 196884 keys",
        med_mon
    );
    println!(
        "  bootstrap speedup            : {:>8.1}x  <-- the startup win",
        med_mon / med_pred
    );
    println!();
    println!("-- 2. warm slot discharge (keys consumed) --");
    println!(
        "  cold slot (regenerate 96768) : {:>8.0} M keys/s",
        cold_kps / 1e6
    );
    println!(
        "  hot slot  (memoized read)    : {:>8.0} M keys/s",
        hot_kps / 1e6
    );
    println!("  caching speedup              : {:>8.1}x", warm_speedup);
    println!();
    println!("-- the catch the benchmark caught --");
    println!(
        "  E8 slot size                 : 96768 keys = {:.0} KB each",
        per_slot_kb
    );
    println!(
        "  slots within Monster's 1.5MB : only ~{:.1}  <-- whole-slot memo is too coarse",
        monster_budget_slots
    );
    println!("  => hybrid caches HOT KEYS, not whole slots; or uses E8 predict() for point hits");
    println!();
    println!(
        "the real win: a cold node answers predict() in ~{:.0}us from a {:.1}KB load,",
        med_pred,
        e8_bytes.len() as f64 / 1e3
    );
    println!(
        "serving the full {} capacity with no warm-up — that's the bootstrap edge.",
        hybrid.capacity()
    );
}
